     Example:
        even_odd_count(-12) ==> (1, 1)
        even_odd_count(123) ==> (1, 2)
    """
    if num < 0:
        return even_odd_count(-num)
    else:
        even_digits = 0
        odd_digits = 0
        for i in str(num):
            if int(i) % 2 == 0:
                even_digits += 1
            else:
                odd_digits += 1
        return (even_digits, odd_digits)
def even_odd_count(num):
