def int_to_mini_roman(number):
    """
    Given a positive integer, obtain its roman numeral equivalent as a string,
    and return it in lowercase.
    Restrictions: 1 <= num <= 1000

    Examples:
    >>> int_to_mini_roman(19) == 'xix'
    >>> int_to_mini_roman(152) == 'clii'
    >>> int_to_mini_roman(426) == 'cdxxvi'
    """
    roman = {1: 'i', 5: 'v', 10: 'x', 50: 'l', 100: 'c', 500: 'd', 1000:'m'}

    mini_roman = []
    while number > 0:
        for i in roman:
            if number >= i:
                mini_roman.append(roman[i])
                number -= i
    return ''.join(mini_roman)

def int_to_mini_roman(number):
    """
    Given a positive integer, obtain its roman numeral equivalent as a string,
    and return it in lowercase.
    Restrictions: 1 <= num <= 1000

    Examples:
    >>> int_to_mini_roman(19) == 'xix'
    >>> int_to_mini_roman(152) == 'clii'
    >>> int_to_mini_roman(426) == 'cdxxvi'
    """
    if number < 1 or number > 1000:
        raise ValueError("Number is outside range [1, 1000].")
    result = []
    for i in range(number):
        num = int(number)
        if num >= 1000:
            result.append("M")
            num -= 1000
        elif num >= 900:
            result.append("CM")
            num -= 900
        elif num >= 500:
            result.append("D")
            num -= 500
        elif num >= 400:
            result.append("CD")
            num -= 400
        elif num >= 100:
            result.append("C")
            num -= 100
        elif num >= 90:
            result.append("XC")
            num -= 90
        elif num >= 50:
            result.append("L")
            num -= 50
        elif num >= 40:
            result.append("XL")
            num -= 40
        elif num >= 10:
            result.append("X")
            num -= 10
        elif num >= 9:
            result.append("IX")
            num -= 9
        elif num >= 5:
            result.append("V")
            num -= 5
        elif num >= 4:
            result.append("IV")
            num -= 4
        elif num >= 1:
            result.append("I")
            num -= 1
        else:
            raise ValueError("Number is outside range [1, 1000].")
    return ''.join(result)

def solve(s):
    """You are given a string s.
    if s[i] is a letter, reverse its case from lower to upper or vise versa, 
    otherwise keep it as it is.
    If the string contains no letters, reverse the string.
    The function should return the resulted string.
    Examples
    solve("1234") = "4321"
    solve("ab") = "AB"
    solve("#a@C") = "#A@c"
    """
    result = []
    for i in s:
        if i.isalpha():
            result.append(i.upper() if i.islower() else i.lower())
        else:
            result.append(i)
    return ''.join(result)
